ull) {\n    inherited.push('strokeDashoffset');\n    o.strokeDashoffset =\n      strokeDasharray && strokeDashoffset ? +strokeDashoffset || 0 : null;\n  }\n  if (strokeLinecap != null) {\n    inherited.push('strokeLinecap');\n    o.strokeLinecap = (strokeLinecap && caps[strokeLinecap]) || 0;\n  }\n  if (strokeLinejoin != null) {\n    inherited.push('strokeLinejoin');\n    o.strokeLinejoin = (strokeLinejoin && joins[strokeLinejoin]) || 0;\n  }\n  if (strokeMiterlimit != null) {\n    inherited.push('strokeMiterlimit');\n    o.strokeMiterlimit =\n      (strokeMiterlimit && typeof strokeMiterlimit !== 'number'\n        ? parseFloat(strokeMiterlimit)\n        : strokeMiterlimit) || 4;\n  }\n  if (vectorEffect != null) {\n    o.vectorEffect = (vectorEffect && vectorEffects[vectorEffect]) || 0;\n  }\n}\n"],"mappings":"0KAAA,oEACA,wEACA,8EAGA,GAAMA,KAAI,CAAG,CACXC,IAAI,CAAE,CADK,CAEXC,MAAM,CAAE,CAFG,CAGXC,KAAK,CAAE,CAHI,CAAb,CAMA,GAAMC,MAAK,CAAG,CACZC,KAAK,CAAE,CADK,CAEZC,KAAK,CAAE,CAFK,CAGZH,KAAK,CAAE,CAHK,CAAd,CAMA,GAAMI,cAAa,CAAG,CACpBC,IAAI,CAAE,CADc,CAEpBC,OAAO,CAAE,CAFW,CAGpBC,gBAAgB,CAAE,CAHE,CAIpB,qBAAsB,CAJF,CAKpBC,OAAO,CAAE,CALW,CAMpBC,GAAG,CAAE,CANe,CAAtB,CASe,QAASC,cAAT,CACbC,CADa,CAEbC,KAFa,CAGbC,SAHa,CAIb,CACA,GACEC,OADF,CAUIF,KAVJ,CACEE,MADF,CAEEC,aAFF,CAUIH,KAVJ,CAEEG,aAFF,CAGEC,aAHF,CAUIJ,KAVJ,CAGEI,aAHF,CAIEC,cAJF,CAUIL,KAVJ,CAIEK,cAJF,CAKEC,eALF,CAUIN,KAVJ,CAKEM,eALF,CAMEC,WANF,CAUIP,KAVJ,CAMEO,WANF,CAOEC,gBAPF,CAUIR,KAVJ,CAOEQ,gBAPF,CAQEC,gBARF,CAUIT,KAVJ,CAQES,gBARF,CASEC,YATF,CAUIV,KAVJ,CASEU,YATF,CAYA,GAAIR,MAAM,EAAI,IAAd,CAAoB,CAClBD,SAAS,CAACU,IAAV,CAAe,QAAf,EACAZ,CAAC,CAACG,MAAF,CAAW,GAAAU,qBAAA,EAAaV,MAAb,CAAX,CACD,CACD,GAAIK,WAAW,EAAI,IAAnB,CAAyB,CACvBN,SAAS,CAACU,IAAV,CAAe,aAAf,EACAZ,CAAC,CAACQ,WAAF,CAAgBM,MAAM,CAACN,WAAD,CAAtB,CACD,CACD,GAAIJ,aAAa,EAAI,IAArB,CAA2B,CACzBF,SAAS,CAACU,IAAV,CAAe,eAAf,EACAZ,CAAC,CAACI,aAAF,CAAkB,GAAAW,uBAAA,EAAeX,aAAf,CAAlB,CACD,CACD,GAAIG,eAAe,EAAI,IAAvB,CAA6B,CAC3BL,SAAS,CAACU,IAAV,CAAe,iBAAf,EACA,GAAMI,WAAU,CACd,